+
+#[test]
+fn invalid_fixture_is_rejected() {
+    let runner = DeterministicRunner::default();
+    let mut invalid = sample_fixture();
+    invalid.fixture_id.clear();
+
+    let error = runner
+        .run_fixture(&invalid)
+        .expect_err("invalid fixture should fail");
