+#[test]
+fn unassigned_entities_default_to_community_zone() {
+    let hierarchy = ZoneHierarchy::standard("maintainer", 1).expect("hierarchy");
+    let zone = hierarchy
+        .zone_for_entity("ext-unassigned")
+        .expect("default zone");
+    assert_eq!(zone.zone_name, "community");
+}
